import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getCurrentUser } from "@/lib/auth";
import { getSelectedAcademicYear } from "@/lib/academicYear";
import {
  apiError,
  validationError,
} from "@/lib/api/errors";
import { recordEvent } from "@/lib/governance/events";
import {
  generateTeacherDNA,
} from "@/lib/intelligence/teacherDNA";




export async function GET(
  request: Request,
  context: any
) {
  try {
    const { id } = await context.params;

    const teacher =
      await prisma.teachers.findUnique({
        where: {
          id: Number(id),
        },
      });

    if (!teacher) {
      return NextResponse.json(
        {
          error: "Teacher Not Found",
        },
        {
          status: 404,
        }
      );
    }

    const assignments =
      await prisma.$queryRawUnsafe<
        TeacherRow[]
      >(
        `
        SELECT
          tca.*,
          c.class_name,
          sec.section_name
        FROM teacher_class_assignments tca
        LEFT JOIN classes c ON c.id = tca.class_id
        LEFT JOIN sections sec ON sec.id = tca.section_id
        WHERE tca.teacher_id = $1
          AND tca.status = 'ACTIVE'
        ORDER BY tca.id DESC
        `,
        Number(id)
      );
    const primaryAssignment =
      assignments[0] || null;

    const attendance =
      await prisma.teacher_attendance.findMany({
        where: {
          teacher_id: Number(id),
        },
      });

    const present =
      attendance.filter(
        (a) =>
          a.status === "PRESENT"
      ).length;

    const attendancePercent =
      attendance.length > 0
        ? Math.round(
            (present /
              attendance.length) *
              100
          )
        : 100;

    const experienceScore =
      Math.min(
        (teacher.experience_years || 0) * 10,
        100
      );

    const impactScore =
      Math.round(
        attendancePercent * 0.6 +
        experienceScore * 0.4
      );

    let rating = "Excellent";

    if (impactScore < 60) {
      rating = "Needs Support";
    } else if (
      impactScore < 80
    ) {
      rating = "Good";
    }

    const teacherHealth =
      Math.round(
        impactScore * 0.5 +
        attendancePercent * 0.3 +
        experienceScore * 0.2
      );

    const burnoutRisk =
      attendancePercent < 70
        ? "HIGH"
        : attendancePercent < 85
        ? "MEDIUM"
        : "LOW";

    const teacherDNA =
  generateTeacherDNA({
    attendancePercent,
    experienceScore,
    impactScore,
  });
  

    const recommendations =
      impactScore >= 80
        ? [
            "Continue mentoring high-performing students",
            "Maintain attendance consistency",
            "Conduct advanced workshops",
            "Share best practices with faculty",
          ]
        : [
            "Increase classroom engagement activities",
            "Improve parent communication",
            "Attend professional development sessions",
            "Track student progress more frequently",
          ];

    return NextResponse.json({
      teacher: {
        ...teacher,
        class_id:
          primaryAssignment?.class_id ??
          null,
        section_id:
          primaryAssignment?.section_id ??
          null,
        class_name:
          primaryAssignment?.class_name ??
          null,
        section_name:
          primaryAssignment?.section_name ??
          null,
        assignments,
      },

      attendancePercent,

      experienceScore,

      impactScore,

      teacherHealth,

      burnoutRisk,

      rating,

      recommendations,

      teacherDNA,
    });
  } catch (error) {
    console.error(error);

    return NextResponse.json(
      {
        error: "Failed",
      },
      {
        status: 500,
      }
    );
  }
}

type TeacherRow = Record<
  string,
  unknown
>;

type TeacherAssignmentInput = {
  class_id: number | null;
  section_id: number | null;
  subject_id: number | null;
  assignment_type: string;
};

export async function PUT(
  request: Request,
  context: any
) {
  try {
    const { id } =
      await context.params;
    const body =
      await request.json();
    const user =
      await getCurrentUser();

    if (!user) {
      return validationError(
        "Login required before updating a teacher."
      );
    }

    const teacherId = Number(id);
    const schoolId =
      user.role === "SUPER_ADMIN"
        ? null
        : Number(user.school_id);
    const academicYear =
      await getSelectedAcademicYear(
        user.school_id
      );
    const academicYearId =
      Number(
        body.academic_year_id ??
          user.academic_year_id ??
          academicYear?.id
      ) || null;
    const classId =
      Number(body.class_id) || null;
    const sectionId =
      Number(body.section_id) || null;
    const subjectId =
      Number(body.subject_id) || null;
    const hasAssignmentsPayload =
      Array.isArray(body.assignments);
    const assignments =
      hasAssignmentsPayload
        ? body.assignments
            .map((assignment: Record<string, unknown>) => ({
              class_id:
                Number(assignment.class_id) ||
                null,
              section_id:
                Number(assignment.section_id) ||
                null,
              subject_id:
                Number(assignment.subject_id) ||
                null,
              assignment_type:
                String(
                  assignment.assignment_type ||
                    body.assignment_type ||
                    "SUBJECT_TEACHER"
                ).toUpperCase(),
            }))
            .filter(
              (assignment: TeacherAssignmentInput) =>
                assignment.class_id ||
                assignment.subject_id
            )
        : classId || subjectId
          ? [
              {
                class_id: classId,
                section_id: sectionId,
                subject_id: subjectId,
                assignment_type:
                  body.assignment_type ||
                  "CLASS_TEACHER",
              },
            ]
          : [];

    if (classId) {
      const classRows =
        await prisma.$queryRawUnsafe<
          TeacherRow[]
        >(
          `
          SELECT id
          FROM classes
          WHERE id = $1
            AND ($2::int IS NULL OR school_id = $2::int)
          `,
          classId,
          schoolId
        );

      if (!classRows.length) {
        return validationError(
          "Selected class does not belong to the selected school."
        );
      }
    }

    if (sectionId) {
      const sectionRows =
        await prisma.$queryRawUnsafe<
          TeacherRow[]
        >(
          `
          SELECT id
          FROM sections
          WHERE id = $1
            AND ($2::int IS NULL OR school_id = $2::int)
            AND ($3::int IS NULL OR class_id = $3::int)
          `,
          sectionId,
          schoolId,
          classId
        );

      if (!sectionRows.length) {
        return validationError(
          "Selected section must belong to the selected class and school."
        );
      }
    }

    const rows =
      await prisma.$queryRawUnsafe<
        TeacherRow[]
      >(
        `
        UPDATE teachers
        SET academic_year_id = $1,
            employee_id = $2,
            first_name = $3,
            last_name = $4,
            gender = $5,
            phone = $6,
            email = $7,
            qualification = $8,
            experience_years = $9,
            joining_date = $10,
            department = $11,
            designation = $12,
            salary = $13,
            address = $14,
            updated_at = CURRENT_TIMESTAMP
        WHERE id = $15
          AND ($16::int IS NULL OR school_id = $16::int)
        RETURNING *
        `,
        academicYearId,
        body.employee_id || null,
        body.first_name || null,
        body.last_name || null,
        body.gender || null,
        body.phone || null,
        body.email || null,
        body.qualification || null,
        body.experience_years
          ? Number(
              body.experience_years
            )
          : null,
        body.joining_date
          ? new Date(
              body.joining_date
            )
          : null,
        body.department || null,
        body.designation || null,
        body.salary
          ? Number(body.salary)
          : null,
        body.address || null,
        teacherId,
        schoolId
      );

    const teacher = rows[0];

    if (!teacher) {
      return validationError(
        "Teacher not found or outside the selected school."
      );
    }

    if (assignments.length > 0) {
      if (hasAssignmentsPayload) {
        await prisma.$executeRawUnsafe(
          `
          UPDATE teacher_class_assignments
          SET status = 'INACTIVE',
              updated_at = CURRENT_TIMESTAMP
          WHERE teacher_id = $1
            AND ($2::int IS NULL OR academic_year_id = $2::int OR academic_year_id IS NULL)
          `,
          teacherId,
          academicYearId
        );
      }

      for (const assignment of assignments) {
      await prisma.$executeRawUnsafe(
        `
        INSERT INTO teacher_class_assignments (
          school_id,
          academic_year_id,
          teacher_id,
          class_id,
          section_id,
          subject_id,
          assignment_type,
          status,
          assigned_by,
          assigned_at,
          created_at,
          updated_at
        )
        VALUES ($1,$2,$3,$4,$5,$6,$7,'ACTIVE',$8,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP)
        ON CONFLICT (
          teacher_id,
          academic_year_id,
          class_id,
          (COALESCE(section_id, 0)),
          (COALESCE(subject_id, 0)),
          assignment_type
        )
        WHERE status = 'ACTIVE'
        DO UPDATE SET
          section_id = EXCLUDED.section_id,
          subject_id = EXCLUDED.subject_id,
          status = 'ACTIVE',
          assigned_by = EXCLUDED.assigned_by,
          updated_at = CURRENT_TIMESTAMP
        `,
        Number(teacher.school_id) ||
          schoolId,
        academicYearId,
        teacherId,
        assignment.class_id,
        assignment.section_id,
        assignment.subject_id,
        assignment.assignment_type,
        user.id || null
      );
      }
    } else if (hasAssignmentsPayload) {
      await prisma.$executeRawUnsafe(
        `
        UPDATE teacher_class_assignments
        SET status = 'INACTIVE',
            updated_at = CURRENT_TIMESTAMP
        WHERE teacher_id = $1
          AND ($2::int IS NULL OR academic_year_id = $2::int OR academic_year_id IS NULL)
        `,
        teacherId,
        academicYearId
      );
    }

    await recordEvent({
      school_id:
        Number(teacher.school_id) ||
        null,
      academic_year_id:
        academicYearId,
      user_id: user.id,
      actor_role: user.role,
      module_name: "teachers",
      event_type: "TEACHER_UPDATED",
      action: "update",
      entity_type: "teacher",
      entity_id: teacherId,
      summary:
        "Teacher record updated",
      payload: {
        assignments,
      },
    });

    return NextResponse.json(
      teacher
    );
  } catch (error) {
    console.error(
      "Teacher update error:",
      error
    );

    return apiError(
      error,
      "Failed to update teacher"
    );
  }
}

const teacherDependentTables = [
  "teacher_attendance",
  "teacher_timelines",
  "teacher_class_assignments",
  "dining_attendance",
  "dining_meal_assignments",
  "dining_special_diets",
  "homework_assignments",
  "timetable_entries",
];

export async function DELETE(
  request: Request,
  context: any
) {
  try {
    const { id } =
      await context.params;
    const user =
      await getCurrentUser();

    if (!user) {
      return validationError(
        "Login required before deleting a teacher."
      );
    }

    const teacherId = Number(id);
    const schoolId =
      user.role === "SUPER_ADMIN"
        ? null
        : Number(user.school_id);
    const rows =
      await prisma.$queryRawUnsafe<
        TeacherRow[]
      >(
        `
        SELECT id, school_id, first_name, last_name, employee_id
        FROM teachers
        WHERE id = $1
          AND ($2::int IS NULL OR school_id = $2::int)
        `,
        teacherId,
        schoolId
      );
    const existing = rows[0];

    if (!existing) {
      return validationError(
        "Teacher not found or outside the selected school."
      );
    }

    await prisma.$transaction(
      async (tx) => {
        await tx.$executeRawUnsafe(
          `
          UPDATE classes
          SET class_teacher_id = NULL
          WHERE class_teacher_id = $1
          `,
          teacherId
        );

        await tx.$executeRawUnsafe(
          `
          UPDATE exam_schedule
          SET invigilator_teacher_id = NULL
          WHERE invigilator_teacher_id = $1
          `,
          teacherId
        );

        for (const table of teacherDependentTables) {
          await tx.$executeRawUnsafe(
            `DELETE FROM ${table} WHERE teacher_id = $1`,
            teacherId
          );
        }

        await tx.$executeRawUnsafe(
          `
          DELETE FROM event_ledger
          WHERE entity_type = 'teacher'
            AND entity_id = $1
          `,
          teacherId
        );

        await tx.$executeRawUnsafe(
          "DELETE FROM teachers WHERE id = $1",
          teacherId
        );
      }
    );

    await recordEvent({
      school_id:
        Number(existing.school_id) ||
        null,
      user_id: user.id,
      actor_role: user.role,
      module_name: "teachers",
      event_type: "TEACHER_DELETED",
      action: "delete",
      entity_type: "school",
      entity_id:
        Number(existing.school_id) ||
        null,
      summary:
        "Teacher record hard deleted",
      payload: {
        teacher_id: teacherId,
        employee_id:
          existing.employee_id,
      },
    });

    return NextResponse.json({
      success: true,
    });
  } catch (error) {
    console.error(
      "Teacher delete error:",
      error
    );

    return apiError(
      error,
      "Failed to delete teacher"
    );
  }
}
